import{_ as o,o as a,c as t,a2 as r}from"./chunks/framework.Bix3-HpO.js";const p=JSON.parse('{"title":"Cloudflare","description":"AkuraiGeo - Cloudflare","frontmatter":{"title":"Cloudflare","description":"AkuraiGeo - Cloudflare","weight":50,"extra":{"order":50},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/akurai-geo/cloudflare"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/akurai-geo/cloudflare"}],["meta",{"property":"og:title","content":"Cloudflare"}],["meta",{"property":"og:description","content":"AkuraiGeo - Cloudflare"}],["meta",{"name":"twitter:title","content":"Cloudflare"}],["meta",{"name":"twitter:description","content":"AkuraiGeo - Cloudflare"}]]},"headers":[],"relativePath":"docs/akurai-geo/cloudflare.md","filePath":"docs/akurai-geo/cloudflare.md"}'),l={name:"docs/akurai-geo/cloudflare.md"};function i(d,e,c,n,s,u){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="cloudflare" tabindex="-1">Cloudflare <a class="header-anchor" href="#cloudflare" aria-label="Permalink to &quot;Cloudflare&quot;">​</a></h1><p>AkuraiGeo requires your website traffic to be routed through Cloudflare because it uses information from a request header provided by Cloudflare.</p><p><code>💁 since version 2.0.0</code> You can use <a href="/docs/akurai-geo/geo-detection">custom geo-detection</a> options without using Cloudflare.</p><hr><h2 id="cloudflare-overview" tabindex="-1">Cloudflare overview <a class="header-anchor" href="#cloudflare-overview" aria-label="Permalink to &quot;Cloudflare overview&quot;">​</a></h2><p>Cloudflare provides a lot of products and solutions to build cloud infrastructures, applications and websites. Among many others, Cloudflare provides services like DNS management, global CDN, SSL certificates, etc.</p><p>Check out more at Cloudflare website at <a href="https://cloudflare.com" target="_blank" rel="noreferrer">https://cloudflare.com</a></p><h3 id="ip-geolocation" tabindex="-1">IP Geolocation <a class="header-anchor" href="#ip-geolocation" aria-label="Permalink to &quot;IP Geolocation&quot;">​</a></h3><p>To make sure the necessary information is provided by Cloudflare, visit your dashboard, select the website you want to enable IP Geolocation for, select &quot;Network&quot; on the left sidebar and scroll down to &quot;IP Geolocation&quot; section and make sure to toggle the button on.</p><h3 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h3><p>AkuraiGeo plugin uses the country code of your website&#39;s visitor&#39;s IP address directly. It doesn&#39;t use the IP address, doesn&#39;t get it from anywhere and therefore can&#39;t store it anywhere.</p>',11)])])}const h=o(l,[["render",i]]);export{p as __pageData,h as default};
